        self._MIN_COOPERATION_THRESHOLD_FOR_MY_C = 0.75
        self._DEFECTION_STREAK_LENGTH = 2
        self._ENDGAME_BUFFER_ROUNDS = max(3, self.r // 4) # Ensure at least 3 rounds, or a quarter if r is large

