    # Get actions from the previous round (current_round - 2 because list is 0-indexed for rounds)
    # E.g., for current_round 2, we need history_of_actions[0]
    previous_round_data = history_of_actions[current_round - 2] # This is a list of actions ['C', 'D', 'C', ...]

