    # Get actions from the previous round (current_round_t - 1)
    # history_of_rounds is 0-indexed, so round (t-1) actions are at index (t-2)
    previous_round_actions = history_of_rounds[current_round_t - 2] 
    
    # Count cooperators in the previous round
    cooperators_in_prev_round = sum(1 for action in previous_round_actions if action == 'C')
    
    # Calculate cooperation proportion
